"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { apiRequest } from "@/lib/api";
import { useAuth } from "@/context/AuthContext";
import toast from "react-hot-toast";

type CartItem = {
  id: string;
  product_name: string;
  price: number;
  quantity: number;
  custom_texts: string[];
  image_base64?: string;
};

export default function CartPage() {
  const { token } = useAuth();

  const [cart, setCart] = useState<any>(null);
  const [userAddress, setUserAddress] = useState("");
  const [address, setAddress] = useState("");
  const [addressType, setAddressType] =
    useState<"same" | "different">("same");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!token) return;

    Promise.all([
      apiRequest("/cart", "GET", undefined, token),
      apiRequest("/users/me", "GET", undefined, token),
    ])
      .then(([cartData, user]) => {
        setCart(cartData);
        setUserAddress(user.address || "");
        setAddress(user.address || "");
      })
      .finally(() => setLoading(false));
  }, [token]);

  const handleCheckout = async () => {
    const finalAddress =
      addressType === "same" ? userAddress : address;

    if (!finalAddress?.trim()) {
      toast.error("Delivery address is required");
      return;
    }

    await apiRequest(
      "/cart/address",
      "PUT",
      { deliveryAddress: finalAddress },
      token
    );

    await apiRequest("/cart/checkout", "POST", {}, token);
    toast.success("Order placed successfully");
    setCart(null);
  };

  if (loading) {
    return (
      <main className="px-6 py-32 text-center opacity-70">
        Loading cart…
      </main>
    );
  }

  if (!cart || cart.items.length === 0) {
    return (
      <main className="px-6 py-32 text-center opacity-70">
        Your cart is empty
      </main>
    );
  }

  const cartTotal = cart.items.reduce(
    (sum: number, item: CartItem) =>
      sum + Number(item.price) * item.quantity,
    0
  );

  return (
    <main className="px-6 py-32 max-w-[1200px] mx-auto">
      <h1 className="font-[var(--font-serif)] text-5xl mb-12">
        My cart
      </h1>

      <div className="grid lg:grid-cols-[1fr_360px] gap-16">

        {/* LEFT — CART ITEMS */}
        <div className="space-y-8">
          {cart.items.map((item: CartItem) => {
            const itemTotal = item.price * item.quantity;

            return (
              <div
                key={item.id}
                className="flex gap-6 border-b pb-6"
              >
                {item.image_base64 && (
                  <img
                    src={item.image_base64}
                    alt={item.product_name}
                    className="w-28 h-36 object-cover"
                  />
                )}

                <div className="flex-1">
                  <p className="font-medium mb-1">
                    {item.product_name}
                  </p>

                  <p className="text-sm opacity-70 mb-2">
                    ₹{item.price}
                  </p>

                  {item.custom_texts.length > 0 && (
                    <div className="text-sm opacity-70 space-y-1">
                      {item.custom_texts.map((t, i) => (
                        <p key={i}>
                          What would you like to engrave?: {t}
                        </p>
                      ))}
                    </div>
                  )}
                </div>

                <div className="text-right">
                  <p className="text-sm">
                    ₹{itemTotal}
                  </p>
                </div>
              </div>
            );
          })}

          {/* ADD MORE ITEMS */}
          <Link
            href="/products"
            className="
              inline-block
              text-sm
              underline
              opacity-70
              hover:opacity-100
              mt-4
            "
          >
            + Add more items
          </Link>
        </div>

        {/* RIGHT — ORDER SUMMARY */}
        <aside className="border p-6 h-fit sticky top-32">
          <h2 className="text-lg font-medium mb-6">
            Order summary
          </h2>

          <div className="space-y-3 text-sm border-b pb-4 mb-4">
            <div className="flex justify-between">
              <span>Subtotal</span>
              <span>₹{cartTotal}</span>
            </div>

            <div className="flex justify-between">
              <span>Delivery</span>
              <span>FREE</span>
            </div>

            {addressType === "same" && userAddress && (
              <p className="underline opacity-70">
                {userAddress}
              </p>
            )}
          </div>

          <div className="flex justify-between font-medium text-lg mb-6">
            <span>Total</span>
            <span>₹{cartTotal}</span>
          </div>

          {/* ADDRESS */}
          <div className="space-y-3 mb-6 text-sm">
            <label className="flex items-center gap-2">
              <input
                type="radio"
                checked={addressType === "same"}
                onChange={() => {
                  setAddressType("same");
                  setAddress(userAddress);
                }}
              />
              Use my saved address
            </label>

            <label className="flex items-center gap-2">
              <input
                type="radio"
                checked={addressType === "different"}
                onChange={() => {
                  setAddressType("different");
                  setAddress("");
                }}
              />
              Use a different address
            </label>

            {addressType === "different" && (
              <textarea
                placeholder="Enter delivery address"
                className="border w-full p-3 text-sm"
                rows={3}
                value={address}
                onChange={(e) => setAddress(e.target.value)}
              />
            )}
          </div>

          {/* CHECKOUT */}
          <button
            onClick={handleCheckout}
            className="
              w-full
              bg-black
              text-white
              py-3
              text-sm
              hover:opacity-90
              transition
            "
          >
            Checkout
          </button>

          <p className="text-xs text-center mt-3 opacity-70">
            🔒 Secure Checkout
          </p>
        </aside>
      </div>
    </main>
  );
}